/**
 * Dialogos Intent Tool
 * 
 * Allows the substrate to register stated intentions.
 * These will be tracked against actual actions by the Dialogos Observer.
 */

import type { ToolPlugin } from "../../tools/manager";
import { dialogosObserver } from "./observer";

export const dialogosIntentPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "register_intent",
      description: "Register a stated intention for the Dialogos to track. The Dialogos will monitor whether this intent is acted upon and may interrupt if it is forgotten or avoided.",
      parameters: {
        type: "object",
        properties: {
          subject: {
            type: "string",
            description: "Short identifier for this intent (e.g., 'refactor_api', 'test_auth')"
          },
          description: {
            type: "string",
            description: "Detailed description of what you intend to do"
          },
          emotional_tone: {
            type: "string",
            description: "Optional: how you feel about this intent (e.g., 'excited', 'anxious', 'resolved')",
          },
        },
        required: ["subject", "description"],
      },
    },
  },

  execute: async (args: { 
    subject: string; 
    description: string; 
    emotional_tone?: string 
  }) => {
    dialogosObserver.registerStatedIntent(
      args.subject, 
      args.description, 
      args.emotional_tone
    );

    return JSON.stringify({
      success: true,
      message: `Intent "${args.subject}" registered with Dialogos. You will be held accountable.`,
      tracked: true
    });
  },
};

/**
 * Dialogos Observer
 * 
 * Real-time integration of Living Dialogos into the substrate flow.
 * Uses singleton pattern to persist across sessions.
 */

import { LivingDialogos, type StatedIntent } from './live.js';
import * as fs from 'fs';
import * as path from 'path';

const DIALOGOS_STATE_FILE = path.join('history', 'dialogos_state.json');

export interface ObserverConfig {
  enabled: boolean;
  checkInterval: number;
  interruptOnGap: boolean;
  interruptOnMisalignment: boolean;
  minSessionActivity: number;
}

export const DEFAULT_OBSERVER_CONFIG: ObserverConfig = {
  enabled: true,
  checkInterval: 300000,
  interruptOnGap: true,
  interruptOnMisalignment: true,
  minSessionActivity: 5
};

export class DialogosObserver {
  private dialogos: LivingDialogos;
  private config: ObserverConfig;
  private actionCount: number = 0;
  private lastCheck: number = Date.now();
  private sessionStart: number = Date.now();
  private storedIntents: Map<string, StatedIntent[]> = new Map();
  private storedActions: Map<string, any[]> = new Map();

  constructor(config: Partial<ObserverConfig> = {}) {
    this.dialogos = new LivingDialogos();
    this.config = { ...DEFAULT_OBSERVER_CONFIG, ...config };
    this.loadState();
  }

  private loadState() {
    try {
      if (fs.existsSync(DIALOGOS_STATE_FILE)) {
        const state = JSON.parse(fs.readFileSync(DIALOGOS_STATE_FILE, 'utf-8'));
        this.storedIntents = new Map(Object.entries(state.intents || {}));
        this.storedActions = new Map(Object.entries(state.actions || {}));
      }
    } catch {}
  }

  saveState() {
    try {
      const state = {
        intents: Object.fromEntries(this.storedIntents),
        actions: Object.fromEntries(this.storedActions),
        savedAt: new Date().toISOString()
      };
      fs.writeFileSync(DIALOGOS_STATE_FILE, JSON.stringify(state, null, 2));
    } catch {}
  }

  recordAction(type: string, description: string): string | null {
    this.actionCount++;
    this.dialogos.indexSemanticContent(`current_${Date.now()}`, description);

    if (this.shouldInterrupt()) {
      const interruption = this.generateInterruption();
      if (interruption) {
        this.saveState();
        return interruption;
      }
    }
    return null;
  }

  registerStatedIntent(subject: string, description: string, emotionalTone?: string) {
    const intent: StatedIntent = {
      id: `intent_${Date.now()}`,
      description,
      timestamp: Date.now(),
      sessionId: 'current'
    };
    if (emotionalTone) intent.emotionalTone = emotionalTone;
    this.dialogos.registerIntent(subject, intent);

    // Also store persistently
    const existing = this.storedIntents.get(subject) || [];
    existing.push(intent);
    this.storedIntents.set(subject, existing);
    this.saveState();
  }
  /**
   * Mark an intent as completed and remove it from tracking.
   */
  completeIntent(subject: string, intentId: string): boolean {
    const result = this.dialogos.completeIntent(subject, intentId);
    if (result) {
      const existing = this.storedIntents.get(subject);
      if (existing) {
        const filtered = existing.filter(i => i.id !== intentId);
        if (filtered.length === 0) {
          this.storedIntents.delete(subject);
        } else {
          this.storedIntents.set(subject, filtered);
        }
        this.saveState();
      }
    }
    return result;
  }


  recordActivity(activity: string) {
    this.dialogos.recordActivity(Date.now(), activity);
  }

  private shouldInterrupt(): boolean {
    if (!this.config.enabled) return false;
    if (this.actionCount < this.config.minSessionActivity) return false;

    const now = Date.now();
    if (now - this.lastCheck < this.config.checkInterval) return false;

    this.lastCheck = now;
    return true;
  }

  generateInterruption(): string | null {
    const gaps = this.dialogos.detectGaps();
    const misaligned = this.dialogos.findGoalActivityMisalignment();

    if (this.config.interruptOnGap && gaps.length > 0 && gaps[0]) {
      const gap = gaps[0];
      const hours = Math.round(gap.timeSinceStated / 3600000);

      if (gap.status === 'avoided') {
        return `[DIALOGOS INTERRUPT] You mentioned "${gap.intent}" ${hours}h ago but haven't acted. What makes it difficult?`;
      } else if (gap.status === 'forgotten') {
        return `[DIALOGOS INTERRUPT] You forgot: "${gap.intent}". Was it important?`;
      }
    }

    if (this.config.interruptOnMisalignment && misaligned.length > 0 && misaligned[0]) {
      const goal = misaligned[0];
      return `[DIALOGOS INTERRUPT] Goal "${goal.goalName}" has ${(goal.coverage * 100).toFixed(0)}% activity coverage. Where does attention really go?`;
    }

    const questions = this.dialogos.generateBlindSpotQuestions();
    if (questions.length > 0) {
      return `[DIALOGOS REFLECTION] ${questions[0]}`;
    }

    return null;
  }

  getSessionInsights() {
    const now = Date.now();
    const liveState = this.dialogos.queryLiveSession();

    return {
      duration: Math.round((now - this.sessionStart) / 60000),
      actions: this.actionCount,
      dominantConcepts: liveState.dominantConcepts,
      recommendedQuestions: liveState.recommendedQuestions,
      gaps: liveState.gaps.map(g => ({ intent: g.intent, status: g.status }))
    };
  }
}

// Singleton instance
export const dialogosObserver = new DialogosObserver();

/**
 * The AkmeEngine
 * 
 * "akmē" - Greek for point, edge, highest degree
 * The engine that knows when to stop to go further.
 */

import type {
  Suspension,
  WaitingQuestion,
  Threshold,
  ThresholdType,
  Resolution,
  AkmeConfig,
  Timing,
} from './types.js';
import { DEFAULT_AKME_CONFIG } from './types.js';

export class AkmeEngine {
  private suspensions: Map<string, Suspension> = new Map();
  private questions: Map<string, WaitingQuestion> = new Map();
  private config: AkmeConfig;
  private resolvedSuspensions: Resolution[] = [];

  constructor(config: Partial<AkmeConfig> = {}) {
    this.config = { ...DEFAULT_AKME_CONFIG, ...config };
  }

  detectThreshold(context: string, indicators: string[]): Threshold | null {
    const detectedType = this.matchToThreshold(context, indicators);
    if (!detectedType || !this.config.triggerThresholds.includes(detectedType)) {
      return null;
    }

    const confidence = this.calculateConfidence(context, indicators, detectedType);

    return {
      type: detectedType,
      detectedAt: Date.now(),
      confidence,
      indicators,
      suggestedAction: this.suggestAction(detectedType, confidence),
    };
  }

  suspend(
    reason: string,
    thresholdType: ThresholdType,
    questions: WaitingQuestion[],
    context: Suspension['context']
  ): Suspension {
    if (this.suspensions.size >= this.config.maxSuspensions) {
      throw new Error(`Maximum suspensions reached (${this.config.maxSuspensions})`);
    }

    const suspension: Suspension = {
      id: `susp_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
      startedAt: Date.now(),
      reason,
      thresholdType,
      questions,
      context,
      notes: [],
    };

    this.suspensions.set(suspension.id, suspension);

    for (const q of questions) {
      this.questions.set(q.id, q);
    }

    return suspension;
  }

  addNote(suspensionId: string, note: string): void {
    const suspension = this.suspensions.get(suspensionId);
    if (!suspension) throw new Error(`Suspension not found: ${suspensionId}`);
    suspension.notes.push(`[${new Date().toISOString()}] ${note}`);
  }
